from flask import Flask, request, jsonify
from pymongo import MongoClient
import bcrypt
from bson.objectid import ObjectId

app = Flask(__name__)

# MongoDB connection settings
MONGO_URI = 'mongodb://localhost:27017/'
DB_NAME = 'cms'

client = MongoClient(MONGO_URI)
db = client[DB_NAME]

# User collection
users_collection = db['users']

# Document collection
documents_collection = db['documents']

# Register user
@app.route('/register', methods=['POST'])
def register_user():
    data = request.json
    if users_collection.find_one({'email': data['email']}):
        return jsonify({'message': 'Email already exists'}), 400

    hashed_password = bcrypt.hashpw(data['password'].encode('utf-8'), bcrypt.gensalt())
    new_user = {
        'name': data['name'],
        'email': data['email'],
        'password': hashed_password
    }
    users_collection.insert_one(new_user)
    return jsonify({'message': 'User created successfully'}), 201

# Login user
@app.route('/login', methods=['POST'])
def login_user():
    data = request.json
    user = users_collection.find_one({'email': data['email']})
    if not user:
        return jsonify({'message': 'Invalid email or password'}), 401

    hashed_password = bcrypt.hashpw(data['password'].encode('utf-8'), bcrypt.gensalt())
    if not bcrypt.checkpw(hashed_password, user['password']):
        return jsonify({'message': 'Invalid email or password'}), 401

    return jsonify({'message': 'Logged in successfully', 'user_id': str(user['_id'])}), 200

# Get all documents
@app.route('/documents', methods=['GET'])
def get_documents():
    documents = list(documents_collection.find())
    return jsonify({'documents': documents})

# Create new document
@app.route('/document', methods=['POST'])
def create_document():
    data = request.json
    new_document = {
        'title': data['title'],
        'content': data['content'],
        'author_id': str(request.headers.get('user-id'))
    }
    documents_collection.insert_one(new_document)
    return jsonify({'message': 'Document created successfully'}), 201

# Get document by ID
@app.route('/document/<id>', methods=['GET'])
def get_document(id):
    document = documents_collection.find_one({'_id': ObjectId(id)})
    if not document:
        return jsonify({'message': 'Document not found'}), 404
    return jsonify({'document': document})

# Update document
@app.route('/document/<id>', methods=['PUT'])
def update_document(id):
    data = request.json
    document = documents_collection.find_one({'_id': ObjectId(id)})
    if not document:
        return jsonify({'message': 'Document not found'}), 404

    documents_collection.update_one({'_id': ObjectId(id)}, {'$set': {
        'title': data['title'],
        'content': data['content']
    }})
    return jsonify({'message': 'Document updated successfully'}), 200

# Delete document
@app.route('/document/<id>', methods=['DELETE'])
def delete_document(id):
    documents_collection.delete_one({'_id': ObjectId(id)})
    return jsonify({'message': 'Document deleted successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)